import React from 'react';
import './App.css'; // Assuming you'll add styles

function App() {
  return (
    <div className="app">
      <header className="app-header">
        <h1>EV Smart Maintenance</h1>
        <p>Monitor and maintain your electric vehicle charging infrastructure</p>
      </header>
      <main className="app-main">
        <div className="dashboard"/>
      </main>
      <footer className="app-footer">
        <p>&copy; FutureNow Smart Maintenance. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;
